+[TestClass]
+public class RefundAsyncTests
+{
+    private PaymentGateway _gateway = null!;
+
+    [TestInitialize]
+    public void Setup() => _gateway = new PaymentGateway();
+
+    [TestMethod]
+    public async Task ValidRefund_ReturnsSuccessWithRefundId()
+    {
+        // Arrange – create a charge first, then refund it
+        var charge = await _gateway.ChargeAsync("tok_valid_visa", 25.00m);
+        Assume.That(charge.Success, "Precondition: charge must succeed");
+
+        // Act
+        var refund = await _gateway.RefundAsync(charge.ChargeId);
+
+        // Assert
+        Assert.IsTrue(refund.Success);
+        Assert.IsFalse(string.IsNullOrWhiteSpace(refund.RefundId));
+    }
+
+    [TestMethod]
+    public async Task RefundNonExistentCharge_ReturnsFailure()
+    {
+        var result = await _gateway.RefundAsync("ch_nonexistent");
+
+        Assert.IsFalse(result.Success);
+    }
+
+    [TestMethod]
+    [DataRow(null)]
+    [DataRow("")]
+    [DataRow("   ")]
+    public async Task NullOrEmptyChargeId_ThrowsArgumentException(string? chargeId)
+    {
+        await Assert.ThrowsExceptionAsync<ArgumentException>(
+            () => _gateway.RefundAsync(chargeId!));
+    }
+
+    [TestMethod]
+    public async Task DoubleRefund_SecondReturnsFailure()
+    {
+        var charge = await _gateway.ChargeAsync("tok_valid_visa", 50.00m);
+        Assume.That(charge.Success, "Precondition: charge must succeed");
+
+        var firstRefund = await _gateway.RefundAsync(charge.ChargeId);
+        Assume.That(firstRefund.Success, "Precondition: first refund must succeed");
+
+        var secondRefund = await _gateway.RefundAsync(charge.ChargeId);
+
+        Assert.IsFalse(secondRefund.Success);
+    }
+
+    [TestMethod]
+    public async Task RefundId_IsUniqueAcrossRefunds()
+    {
+        var charge1 = await _gateway.ChargeAsync("tok_valid_visa", 10.00m);
+        var charge2 = await _gateway.ChargeAsync("tok_valid_visa", 20.00m);
+
+        var refund1 = await _gateway.RefundAsync(charge1.ChargeId);
+        var refund2 = await _gateway.RefundAsync(charge2.ChargeId);
+
+        Assert.AreNotEqual(refund1.RefundId, refund2.RefundId);
+    }
+}
